using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentDbService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
        => await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
        => await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        db.Shipments.Update(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task DeleteShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
        }
    }
}
```

