@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3 row">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="CreateShipment">
                <div class="row g-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Tracking #" @bind-value="newShipment.TrackingNumber" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Origin" @bind-value="newShipment.Origin" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Destination" @bind-value="newShipment.Destination" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Recipient" @bind-value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Customer Email" @bind-value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-1">
                        <button type="submit" class="btn btn-success">Save</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Recipient</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                    <td>@s.ShippedDate.ToShortDateString()</td>
                    <td>@(s.EstimatedDelivery?.ToShortDateString() ?? "—")</td>
                    <td>@s.RecipientName</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@s.Status" @onchange="e => UpdateStatus(s, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private Shipment newShipment = new() { ShippedDate = DateTime.UtcNow };

    private IEnumerable<Shipment> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreateForm = !showCreateForm;

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new() { ShippedDate = DateTime.UtcNow };
        showCreateForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            shipment.Status = newStatus;
            await ShipmentService.UpdateShipmentAsync(shipment);
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "info",
        ShipmentStatus.Delayed => "warning",
        ShipmentStatus.Returned => "danger",
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "dark",
        _ => "secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p><em>Searching...</em></p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number "<strong>@searchedNumber</strong>".</div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge bg-@GetStatusColor(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToShortDateString()</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">@(shipment.EstimatedDelivery?.ToShortDateString() ?? "Pending")</dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success">@shipment.ActualDelivery.Value.ToShortDateString()</dd>
                        }
                    </dl>
                </div>
            </div>
            <div class="row mt-3">
                <div class="col-12">
                    <dt>Recipient</dt>
                    <dd>@shipment.RecipientName</dd>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private Shipment? shipment;
    private bool searched;
    private bool isLoading;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isLoading = true;
        searched = false;
        shipment = null;
        StateHasChanged();

        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        isLoading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await TrackShipment();
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "info",
        ShipmentStatus.Delayed => "warning",
        ShipmentStatus.Returned => "danger",
        _ => "secondary"
    };
}

